import sys

n, m = map(int, sys.stdin.readline().split())
grid = [sys.stdin.readline().strip() for _ in range(n)]

def is_valid(rows, cols):
    return len(rows) == len(set(rows)) and len(cols) == len(set(cols))

def is_valid_grid(grid, rows, cols):
    for i in range(n):
        for j in range(m):
            if grid[i][j] == '#' and (i not in rows or j not in cols):
                return False
    return True

def is_valid_sequence(grid, rows, cols):
    if not is_valid(rows, cols):
        return False
    if not is_valid_grid(grid, rows, cols):
        return False
    return True

def solve(grid, rows, cols):
    if not is_valid_sequence(grid, rows, cols):
        return False
    if len(rows) == n and len(cols) == m:
        return True
    for i in range(rows[-1]+1, n):
        for j in range(m):
            if solve(grid, rows + [i], cols + [j]):
                return True
    return False

if solve(grid, [0], [0]):
    print("Yes")
else:
    print("No")
